import{_ as t,o as a,c as i,ae as r}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"SingleTap by Digital Turbine","description":"","frontmatter":{"title":"SingleTap by Digital Turbine","slug":"singletap-configuration"},"headers":[],"relativePath":"marketer-hub/singletap-configuration.md","filePath":"marketer-hub/singletap-configuration.md"}'),n={name:"marketer-hub/singletap-configuration.md"};function o(s,e,l,p,d,c){return a(),i("div",null,[...e[0]||(e[0]=[r('<p><em>[Image: 1328]</em>.png &quot;Digital Turbine + branch.png&quot;)</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p><a href="https://www.digitalturbine.com/" target="_blank" rel="noreferrer">SingleTap by Digital Turbine</a> simplifies app advertising, recommendation, delivery and tracking. Maximize revenue, increase user engagement and save cost.</p><p><strong>PARTNER CAPABILITIES</strong></p><table tabindex="0"><thead><tr><th>Partner Capabilities</th><th>Details</th></tr></thead><tbody><tr><td>Company Type</td><td>Contact support at SingleTap by Digital Turbine for more information.</td></tr><tr><td>Deep Linking</td><td>Supported</td></tr><tr><td>Attribution</td><td>Contact support at SingleTap by Digital Turbine for more information.</td></tr><tr><td>Ad Campaign Types</td><td>Contact support at SingleTap by Digital Turbine for more information.</td></tr><tr><td>Ad Formats</td><td>Contact support at SingleTap by Digital Turbine for more information.</td></tr><tr><td>Click Types</td><td>Contact support at SingleTap by Digital Turbine for more information.</td></tr><tr><td>Supported Platforms</td><td>Contact support at SingleTap by Digital Turbine for more information.</td></tr><tr><td>Link Wrapping</td><td>Contact support at SingleTap by Digital Turbine for more information.</td></tr><tr><td>Cost Ingestion Support</td><td>Contact support at SingleTap by Digital Turbine for more information.</td></tr><tr><td>Cost Ingestion Types</td><td>Contact support at SingleTap by Digital Turbine for more information.</td></tr><tr><td>Pricing Models</td><td>Contact support at SingleTap by Digital Turbine for more information.</td></tr></tbody></table><h2 id="_1-complete-ads-prerequisites" tabindex="-1">1. Complete Ads Prerequisites <a class="header-anchor" href="#_1-complete-ads-prerequisites" aria-label="Permalink to &quot;1. Complete Ads Prerequisites&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">DEVELOPER MAY BE REQUIRED</p><p>The following Ads prerequisite includes providing URI schemes and other components that may require a developer:</p><ul><li><a href="https://branch.dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer"><strong>Add Deep Link Routing &amp; Required Redirects</strong></a></li></ul></div><div class="warning custom-block"><p class="custom-block-title">DEVELOPER REQUIRED</p><p>The following Ads prerequisites involve app code changes:</p><ul><li><a href="./native-sdks-overview.html"><strong>Implement the Branch SDK</strong></a></li></ul></div><h2 id="_2-enable-the-integration" tabindex="-1">2. Enable the Integration <a class="header-anchor" href="#_2-enable-the-integration" aria-label="Permalink to &quot;2. Enable the Integration&quot;">​</a></h2><ol><li>Visit the <a href="https://dashboard.branch.io/ads" target="_blank" rel="noreferrer"><strong>Ads</strong></a> page on the Branch dashboard.</li><li>Select <a href="https://dashboard.branch.io/ads/partner-management" target="_blank" rel="noreferrer"><strong>Partner Management</strong></a> from the sidebar.</li><li>Search for SingleTap by Digital Turbine.</li><li>Select <strong>SingleTap by Digital Turbine</strong> and click <strong>Save &amp; Enable</strong>.</li></ol><p>.png &quot;Screen Shot 2020-12-03 at 11.25.33 AM.png&quot;)</p><h2 id="_3-enable-postbacks" tabindex="-1">3. Enable Postbacks <a class="header-anchor" href="#_3-enable-postbacks" aria-label="Permalink to &quot;3. Enable Postbacks&quot;">​</a></h2><p>When Branch measures a conversion (install or other event), it determines which ad network or partner is responsible for generating the action, then attributes credit to the proper partner accordingly. Branch notifies the Ad partner of these events via postbacks which are turned on when you enable any Ads integrated partner.</p><p>Basic postbacks will automatically be activated for events like Install and Purchase when you enable your ad partner.</p><p>Branch’s postback system is highly <a href="./basic-postback-configuration.html">customizable</a>; you can set up postbacks for specific events, as well as specific subsections of events, filtered by link data, user data or event properties.</p><p>You can then <a href="./branch-universal-ads-advanced.html#addingenabling-more-postbacks">add additional postbacks</a>, for example, if you wanted to add postbacks for custom events that are specific to your app like Account Created. You can also <a href="./branch-universal-ads-advanced.html#addingenabling-more-postbacks">edit postbacks</a> if there&#39;s additional data you really need to pass along to your ad partner.</p><p>.png &quot;2418cf9-Screenshot_2020-12-01_221152.png&quot;)</p><div class="danger custom-block"><p class="custom-block-title">Troubleshoot Postbacks</p><p>There may be times when you need to reset a partner&#39;s settings; i.e. when a partner updates their postback templates or when perhaps you&#39;ve made a mistake during partner setup. Resetting a partner&#39;s settings allows you to re-enable the partner integration with the correct information to accurately measure and attribute conversion.</p><p>Note, by resetting your partner settings, this will:</p><ul><li>Disable the ad partner</li><li>Clear out all of your saved credentials and postbacks that are already setup</li><li>Return the ad partner to its basic configuration</li></ul><p><a href="./reset-my-ad-partners-settings.html">Learn more here on how to reset your ad partner&#39;s settings.</a></p></div><h2 id="_4-verify-integration-setup" tabindex="-1">4. Verify Integration Setup <a class="header-anchor" href="#_4-verify-integration-setup" aria-label="Permalink to &quot;4. Verify Integration Setup&quot;">​</a></h2><details><summary>View Link Parameters</summary><p>By default, Branch automatically appends partner-specific link parameters during the link creation process. When a user clicks on the link, SingleTap by Digital Turbine provides the appropriate parameter values which Branch ingests and uses for attribution and reporting purposes.</p><p>Below are the link parameters that Branch automatically appends for this ad partner:</p><p>.png &quot;Screen Shot 2020-12-03 at 11.32.45 AM.png&quot;)</p></details><details><summary>View Attribution Windows</summary><p>Branch employs <a href="./attribution-windows-link-settings.html">Attribution Windows</a> at both the app level and the ad partner level. When you enable SingleTap by Digital Turbine, Branch uses the attribution windows you&#39;ve selected at the app level.</p><p>However, you can choose to use the attribution windows provided specifically by SingleTap by Digital Turbine. To do so, toggle the <strong>Use Ad Partner Attribution Windows</strong> to on. Please keep in mind that only conversions attributed to this ad partner will use these specific windows; otherwise, the app-level windows prevail.</p><p>.png &quot;Screen Shot 2020-12-03 at 11.32.58 AM.png&quot;)</p></details><details><summary>Test Postbacks</summary><p>Testing your configuration is a very important step that we highly recommend you take the time to complete before going live with marketing campaigns.</p><p>Learn how to <a href="./testing-postbacks.html">Test Postbacks</a></p><p>.png &quot;Screen Shot 2020-12-03 at 11.33.23 AM.png&quot;)</p></details><h2 id="_5-create-a-branch-link" tabindex="-1">5. Create a Branch Link <a class="header-anchor" href="#_5-create-a-branch-link" aria-label="Permalink to &quot;5. Create a Branch Link&quot;">​</a></h2><p>If you are running paid advertising campaigns, you&#39;ll want to create a Branch Ad Link so we can accurately attribute resulting app conversions to the appropriate advertising partner.</p><ol><li>Create a <a href="./create-quick-links.html">Branch Short Link</a></li><li>Make your Branch Link compatible with SingleTap™.</li><li>Retrieve your base SingleTap™ link from your SingleTap by Digital Turbine Account Manager.</li><li>Add <code>&amp;dvURL=</code> followed by your URL encoded Branch link to the end of your Digital Turbine URL.</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://delivers.dtignite.com/v2/delivers/clickAd.jsp?siteId=11365&amp;campaignId=28394</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://skdm3.app.link/pzBYIfsilZ</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://delivers.dtignite.com/v2/delivers/clickAd.jsp?siteId=11365&amp;campaignId=28394&amp;dvURL=https%3A%2F%2Fskdm3.app.link%2FpzBYIfsilZ</span></span></code></pre></div><ol start="5"><li><p>Create a <a href="./create-journey-banner-or-interstitial.html">Branch Journey</a>.</p></li><li><p>When customizing your Journey’s appearance:</p><ol><li>Select the &quot;Open&quot; CTA on your Journey.</li><li>In the “Deep Link Data” section, add an entry with the key <code>$journeys_cta</code> and the value as your SingleTap URL from step 4 above.</li></ol></li></ol><div class="warning custom-block"><p class="custom-block-title">To avoid split analytics data:</p><ul><li>The ~campaign value for your Short Link should match the name of your Journey.</li><li>The ~channel value for your Short Link and your Journey should match.</li><li>The ~feature value for your Short Link should be set to <code>journeys</code>.</li><li>A parameter should be added to your Short Link in the “Deep Linking” section with the key <code>$3p</code> and the value <code>a_digital_turbine</code>.</li></ul></div><h2 id="more-information" tabindex="-1">More information <a class="header-anchor" href="#more-information" aria-label="Permalink to &quot;More information&quot;">​</a></h2><p>For more information about SingleTap by Digital Turbine, including how to use Branch Journeys with SingleTap, please visit our <a href="./singletap-advanced.html">developer documentation</a>.</p>',32)])])}const g=t(n,[["render",o]]);export{h as __pageData,g as default};
